import React, { createContext, useContext, useState, useEffect, ReactNode, useCallback } from 'react';

// Storage key for language preference
const LANGUAGE_STORAGE_KEY = 'thundra_language_preference';

// Helper functions for persistent storage
const saveLanguagePreference = (lang: string) => {
  try {
    // Save to localStorage
    localStorage.setItem(LANGUAGE_STORAGE_KEY, lang);
    // Save to cookie (expires in 1 year)
    document.cookie = `${LANGUAGE_STORAGE_KEY}=${lang};path=/;max-age=31536000;SameSite=Lax`;
  } catch (e) {
    console.warn('Could not save language preference:', e);
  }
};

const getStoredLanguagePreference = (): string | null => {
  try {
    // Try localStorage first
    const stored = localStorage.getItem(LANGUAGE_STORAGE_KEY);
    if (stored) return stored;
    // Fallback to cookie
    const cookies = document.cookie.split(';');
    for (const cookie of cookies) {
      const [key, value] = cookie.trim().split('=');
      if (key === LANGUAGE_STORAGE_KEY) return value;
    }
  } catch (e) {
    console.warn('Could not read language preference:', e);
  }
  return null;
};

