interface LanguageContextType {
  language: LanguageCode;
  setLanguage: (code: LanguageCode) => void;
  t: Translations;
}

const LanguageContext = createContext<LanguageContextType | undefined>(undefined);

export function LanguageProvider({ children }: { children: ReactNode }) {
  const [language, setLanguage] = useState<LanguageCode>(() => {
    const stored = localStorage.getItem('thundra-language');
    return (stored as LanguageCode) || 'en';
  });

  useEffect(() => {
    localStorage.setItem('thundra-language', language);
  }, [language]);

  // Merge footer translations with defaults for missing keys
  const baseTranslation = translations[language] || translations.en;
  const defaultFooter = enTranslations.footer;
  const t: Translations = {
    ...baseTranslation,
    footer: {
      ...defaultFooter,
      ...baseTranslation.footer,
    } as FooterTranslations,
  };

  return (
    <LanguageContext.Provider value={{ language, setLanguage, t }}>
      {children}
    </LanguageContext.Provider>
  );
}

export function useLanguage() {
  const context = useContext(LanguageContext);
  if (context === undefined) {
    throw new Error('useLanguage must be used within a LanguageProvider');
  }
  return context;
}
